import React, { useState, useEffect } from 'react';
import clsx from 'clsx';
import {
  Card,
  ConfirmDialog,
  SkeletonCard,
  toast,
  useConfirm,
} from '@adopt-dont-shop/lib.components';
import { FiCalendar, FiPlus } from 'react-icons/fi';
import * as styles from './Events.css';

// Event Components
import EventList from '../components/events/EventList';
import EventFilters from '../components/events/EventFilters';
import EventForm from '../components/events/EventForm';
import EventDetails from '../components/events/EventDetails';
import EventCalendar from '../components/events/EventCalendar';

// Services
import { eventsService } from '../services/eventsService';

// Types
import {
  Event,
  CreateEventInput,
  UpdateEventInput,
  EventFilter,
  CalendarView,
  EventAttendee,
} from '../types/events';

const Events: React.FC = () => {
  // State for events data
  const [events, setEvents] = useState<Event[]>([]);
  const [filteredEvents, setFilteredEvents] = useState<Event[]>([]);
  const [selectedEvent, setSelectedEvent] = useState<Event | null>(null);
  const [eventAttendees, setEventAttendees] = useState<EventAttendee[]>([]);

  // State for filters and view
  const [filters, setFilters] = useState<EventFilter>({
    type: 'all',
    status: 'all',
    searchQuery: '',
  });
  const [view, setView] = useState<CalendarView>('list');

  // State for modals
  const [showCreateModal, setShowCreateModal] = useState(false);
  const [showEditModal, setShowEditModal] = useState(false);
  const [showDetailsModal, setShowDetailsModal] = useState(false);
  const [eventToEdit, setEventToEdit] = useState<Event | null>(null);

  // State for loading and errors
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  // In-flight flag to prevent duplicate create/update/delete submissions.
  const [submitting, setSubmitting] = useState(false);

  // ADS-586: confirm dialog for destructive event deletion.
  const { confirm, confirmProps } = useConfirm();

  // Fetch events on mount
  useEffect(() => {
    let cancelled = false;

    const load = async () => {
      setLoading(true);
      setError(null);
      try {
        const fetchedEvents = await eventsService.getEvents();
        if (!cancelled) {
          setEvents(fetchedEvents);
        }
      } catch (err) {
        if (!cancelled) {
          console.error('Failed to fetch events:', err);
          setError('Failed to load events. Please try again.');
        }
      } finally {
        if (!cancelled) {
          setLoading(false);
        }
      }
    };

    load();
    return () => {
      cancelled = true;
    };
  }, []);

  // Apply filters whenever events or filters change
  useEffect(() => {
    applyFilters();
  }, [events, filters]);

  /**
   * Apply filters to events
   */
  const applyFilters = () => {
    let filtered = [...events];

    // Filter by type
    if (filters.type && filters.type !== 'all') {
      filtered = filtered.filter(event => event.type === filters.type);
    }

    // Filter by status
    if (filters.status && filters.status !== 'all') {
      filtered = filtered.filter(event => event.status === filters.status);
    }

    // Filter by search query
    if (filters.searchQuery) {
      const query = filters.searchQuery.toLowerCase();
      filtered = filtered.filter(
        event =>
          event.name.toLowerCase().includes(query) ||
          event.description.toLowerCase().includes(query)
      );
    }

    // Filter by date range
    if (filters.dateRange) {
      filtered = filtered.filter(event => {
        const eventDate = new Date(event.startDate);
        return eventDate >= filters.dateRange!.start && eventDate <= filters.dateRange!.end;
      });
    }

    // Filter by assigned staff
    if (filters.assignedStaff) {
      filtered = filtered.filter(event => event.assignedStaff?.includes(filters.assignedStaff!));
    }

    // Filter by public/private
    if (filters.isPublic !== undefined) {
      filtered = filtered.filter(event => event.isPublic === filters.isPublic);
    }

    setFilteredEvents(filtered);
  };

  /**
   * Handle event creation
   */
  const handleCreateEvent = async (eventData: CreateEventInput) => {
    if (submitting) {
      return;
    }
    setSubmitting(true);
    try {
      const newEvent = await eventsService.createEvent(eventData);
      setEvents(prev => [newEvent, ...prev]);
      setShowCreateModal(false);
    } catch (err) {
      console.error('Failed to create event:', err);
      toast.error('Failed to create event. Please try again.', {
        action: { label: 'Retry', onClick: () => handleCreateEvent(eventData) },
      });
    } finally {
      setSubmitting(false);
    }
  };

  /**
   * Handle event update
   */
  const handleUpdateEvent = async (eventData: CreateEventInput) => {
    if (!eventToEdit || submitting) {
      return;
    }

    setSubmitting(true);
    try {
      const updates: UpdateEventInput = {
        ...eventData,
      };
      const updatedEvent = await eventsService.updateEvent(eventToEdit.id, updates);
      setEvents(prev => prev.map(event => (event.id === updatedEvent.id ? updatedEvent : event)));
      setShowEditModal(false);
      setEventToEdit(null);

      // Update selected event if it's being viewed
      if (selectedEvent?.id === updatedEvent.id) {
        setSelectedEvent(updatedEvent);
      }
    } catch (err) {
      console.error('Failed to update event:', err);
      toast.error('Failed to update event. Please try again.', {
        action: { label: 'Retry', onClick: () => handleUpdateEvent(eventData) },
      });
    } finally {
      setSubmitting(false);
    }
  };

  /**
   * Handle event deletion
   */
  const handleDeleteEvent = async (eventId: string) => {
    if (submitting) {
      return;
    }
    const confirmed = await confirm({
      title: 'Delete event?',
      message: 'Are you sure you want to delete this event? This action cannot be undone.',
      confirmText: 'Delete event',
      cancelText: 'Cancel',
      variant: 'danger',
    });
    if (!confirmed) {
      return;
    }

    setSubmitting(true);
    try {
      await eventsService.deleteEvent(eventId);
      setEvents(prev => prev.filter(event => event.id !== eventId));
      setShowDetailsModal(false);
      setSelectedEvent(null);
    } catch (err) {
      console.error('Failed to delete event:', err);
      toast.error('Failed to delete event. Please try again.', {
        action: { label: 'Retry', onClick: () => handleDeleteEvent(eventId) },
      });
    } finally {
      setSubmitting(false);
    }
  };

  /**
   * Handle event status update
   */
  const handleUpdateEventStatus = async (eventId: string, status: string) => {
    if (submitting) return;

    setSubmitting(true);
    try {
      const updatedEvent = await eventsService.updateEventStatus(eventId, status);
      setEvents(prev => prev.map(event => (event.id === updatedEvent.id ? updatedEvent : event)));

      // Update selected event
      if (selectedEvent?.id === updatedEvent.id) {
        setSelectedEvent(updatedEvent);
      }
    } catch (err) {
      console.error('Failed to update event status:', err);
      toast.error('Failed to update event status. Please try again.', {
        action: { label: 'Retry', onClick: () => handleUpdateEventStatus(eventId, status) },
      });
    } finally {
      setSubmitting(false);
    }
  };

  /**
   * Handle event click - show details
   */
  const handleEventClick = async (event: Event) => {
    setSelectedEvent(event);
    setShowDetailsModal(true);

    // Fetch attendees if registration is required
    if (event.registrationRequired) {
      try {
        const attendees = await eventsService.getEventAttendees(event.id);
        setEventAttendees(attendees);
      } catch (err) {
        console.error('Failed to fetch attendees:', err);
        setEventAttendees([]);
      }
    }
  };

  /**
   * Handle edit button click from details modal
   */
  const handleEditClick = () => {
    if (selectedEvent) {
      setEventToEdit(selectedEvent);
      setShowDetailsModal(false);
      setShowEditModal(true);
    }
  };

  /**
   * Handle attendee check-in
   */
  const handleCheckInAttendee = async (userId: string) => {
    if (!selectedEvent) {
      return;
    }

    try {
      await eventsService.checkInAttendee(selectedEvent.id, userId);
      // Refresh attendees list
      const updatedAttendees = await eventsService.getEventAttendees(selectedEvent.id);
      setEventAttendees(updatedAttendees);
    } catch (err) {
      console.error('Failed to check in attendee:', err);
      toast.error('Failed to check in attendee. Please try again.', {
        action: { label: 'Retry', onClick: () => handleCheckInAttendee(userId) },
      });
    }
  };

  /**
   * Handle closing modals
   */
  const handleCloseModal = (modalType: 'create' | 'edit' | 'details') => {
    switch (modalType) {
      case 'create':
        setShowCreateModal(false);
        break;
      case 'edit':
        setShowEditModal(false);
        setEventToEdit(null);
        break;
      case 'details':
        setShowDetailsModal(false);
        setSelectedEvent(null);
        setEventAttendees([]);
        break;
    }
  };

  if (error) {
    return (
      <div className={styles.pageContainer}>
        <div className={styles.pageHeader}>
          <div className={styles.headerTitle}>
            <h1>Event Management</h1>
          </div>
        </div>
        <div className={styles.errorState}>
          <p>{error}</p>
        </div>
      </div>
    );
  }

  return (
    <div className={styles.pageContainer}>
      <div className={styles.pageHeader}>
        <div className={styles.headerTop}>
          <div className={styles.headerTitle}>
            <h1>Event Management</h1>
            <p>Plan and coordinate adoption events, fundraisers, and volunteer activities</p>
          </div>

          <div className={styles.headerActions}>
            <button
              className={styles.primaryButton}
              onClick={() => setShowCreateModal(true)}
              disabled={loading}
            >
              <FiPlus />
              Create Event
            </button>
          </div>
        </div>

        <EventFilters
          filters={filters}
          onFiltersChange={setFilters}
          view={view}
          onViewChange={setView}
        />
      </div>

      <div className={styles.contentArea}>
        {loading ? (
          <div style={{ display: 'flex', flexDirection: 'column', gap: '1rem' }}>
            {Array.from({ length: 3 }, (_, i) => (
              <SkeletonCard key={i} lines={3} />
            ))}
          </div>
        ) : filteredEvents.length === 0 && !loading ? (
          <Card>
            <div className={styles.emptyState}>
              <FiCalendar />
              <h3>No Events Found</h3>
              <p>
                {events.length === 0
                  ? "You haven't created any events yet. Get started by creating your first event!"
                  : 'No events match your current filters. Try adjusting your search criteria.'}
              </p>
              {events.length === 0 && (
                <button className={styles.primaryButton} onClick={() => setShowCreateModal(true)}>
                  <FiPlus />
                  Create Your First Event
                </button>
              )}
            </div>
          </Card>
        ) : view === 'list' ? (
          <EventList events={filteredEvents} onEventClick={handleEventClick} loading={loading} />
        ) : (
          <EventCalendar events={filteredEvents} onEventClick={handleEventClick} />
        )}
      </div>

      {/* Create Event Modal */}
      <div
        className={clsx(styles.modal, showCreateModal ? styles.modalOpen : styles.modalClosed)}
        onClick={() => handleCloseModal('create')}
      >
        <div
          className={styles.modalContent}
          role="dialog"
          aria-modal="true"
          aria-labelledby="create-event-title"
          onClick={e => e.stopPropagation()}
          onKeyDown={e => e.key === 'Escape' && handleCloseModal('create')}
        >
          <div className={styles.modalHeader}>
            <h2 id="create-event-title" className={styles.modalTitle}>
              Create New Event
            </h2>
            <button
              className={styles.closeButton}
              aria-label="Close"
              onClick={() => handleCloseModal('create')}
            >
              &times;
            </button>
          </div>
          <div className={styles.modalBody}>
            <EventForm
              onSubmit={handleCreateEvent}
              onCancel={() => handleCloseModal('create')}
              isEditing={false}
              submitting={submitting}
            />
          </div>
        </div>
      </div>

      {/* Edit Event Modal */}
      <div
        className={clsx(styles.modal, showEditModal ? styles.modalOpen : styles.modalClosed)}
        onClick={() => handleCloseModal('edit')}
      >
        <div
          className={styles.modalContent}
          role="dialog"
          aria-modal="true"
          aria-labelledby="edit-event-title"
          onClick={e => e.stopPropagation()}
          onKeyDown={e => e.key === 'Escape' && handleCloseModal('edit')}
        >
          <div className={styles.modalHeader}>
            <h2 id="edit-event-title" className={styles.modalTitle}>
              Edit Event
            </h2>
            <button
              className={styles.closeButton}
              aria-label="Close"
              onClick={() => handleCloseModal('edit')}
            >
              &times;
            </button>
          </div>
          <div className={styles.modalBody}>
            {eventToEdit && (
              <EventForm
                initialData={{
                  name: eventToEdit.name,
                  description: eventToEdit.description,
                  type: eventToEdit.type,
                  startDate: eventToEdit.startDate,
                  endDate: eventToEdit.endDate,
                  location: eventToEdit.location,
                  capacity: eventToEdit.capacity,
                  registrationRequired: eventToEdit.registrationRequired,
                  featuredPets: eventToEdit.featuredPets,
                  assignedStaff: eventToEdit.assignedStaff,
                  isPublic: eventToEdit.isPublic,
                  imageUrl: eventToEdit.imageUrl,
                }}
                onSubmit={handleUpdateEvent}
                onCancel={() => handleCloseModal('edit')}
                isEditing={true}
                submitting={submitting}
              />
            )}
          </div>
        </div>
      </div>

      {/* Event Details Modal */}
      <div
        className={clsx(styles.modal, showDetailsModal ? styles.modalOpen : styles.modalClosed)}
        onClick={() => handleCloseModal('details')}
      >
        <div
          className={styles.modalContent}
          role="dialog"
          aria-modal="true"
          aria-labelledby="event-details-title"
          onClick={e => e.stopPropagation()}
          onKeyDown={e => e.key === 'Escape' && handleCloseModal('details')}
        >
          <div className={styles.modalHeader}>
            <h2 id="event-details-title" className={styles.modalTitle}>
              Event Details
            </h2>
            <button
              className={styles.closeButton}
              aria-label="Close"
              onClick={() => handleCloseModal('details')}
            >
              &times;
            </button>
          </div>
          <div className={styles.modalBody}>
            {selectedEvent && (
              <EventDetails
                event={selectedEvent}
                attendees={eventAttendees}
                onEdit={handleEditClick}
                onDelete={() => handleDeleteEvent(selectedEvent.id)}
                onUpdateStatus={status => handleUpdateEventStatus(selectedEvent.id, status)}
                onCheckInAttendee={handleCheckInAttendee}
              />
            )}
          </div>
        </div>
      </div>

      <ConfirmDialog {...confirmProps} />
    </div>
  );
};

export default Events;
